urlset:
{% for post in posts %}

  {{ post.permalink | uriencode }}
  {% if post.updated %}
  {{ post.updated | formatDate }}
  {% elif post.date %}
  {{ post.date | formatDate }}
  {% else %}
  {{ sNow | formatDate }}
  {% endif %}
  {% if post.layout == 'page' %}
  monthly
  0.6
  {% elif post.layout == 'post' and (post.sticky or post._sitemap_recent) %}
  weekly
  0.8
  {% else %}
  monthly
  0.5
  {% endif %}
  {% if post.cover and post.cover.length > 0 %}

    {{ (config.url + post.cover) | uriencode }}
    {% if post.title %}
    {{ post.title }}
    {% endif %}
    {% if post.excerpt %}
    {{ post.excerpt | escape }}
    {% endif %}

  {% endif %}

{% endfor %}


  {{ config.url | uriencode }}
  {{ sNow | formatDate }}
  daily
  1.0


{% for tag in tags %}

  {{ tag.permalink | uriencode }}
  {{ sNow | formatDate }}
  monthly
  0.3

{% endfor %}

{% for cat in categories %}

  {{ cat.permalink | uriencode }}
  {{ sNow | formatDate }}
  monthly
  0.3

{% endfor %}
